export function UpdatePasswordForm({
  className,
  ...props
}: React.ComponentPropsWithoutRef<"div">) {
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const router = useRouter();

  const handleForgotPassword = async (e: React.FormEvent) => {
    e.preventDefault();
    const supabase = createClient();
    setIsLoading(true);
    setError(null);

    try {
      const { error } = await supabase.auth.updateUser({ password });
      if (error) throw error;
      // Update this route to redirect to an authenticated route. The user already has an active session.
      router.push("/protected");
    } catch (error: unknown) {
      setError(error instanceof Error ? error.message : "An error occurred");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className={cn("flex flex-col gap-6", className)} {...props}>
      <Card>
        <CardHeader>
          <CardTitle className="text-2xl">Reset Your Password</CardTitle>
          <CardDescription>
            Please enter your new password below.
          </CardDescription>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleForgotPassword}>
            <div className="flex flex-col gap-6">
              <div className="grid gap-2">
                <Label htmlFor="password">New password</Label>
                <InputGroup>
                  <InputGroupAddon>
                    <Lock />
                  </InputGroupAddon>
                  <InputGroupInput
                    id="password"
                    type={showPassword ? "text" : "password"}
                    placeholder="New password"
                    required
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                  />
                  <InputGroupAddon align={"inline-end"}>
                    <InputGroupButton
                      className="cursor-pointer hover:bg-muted transition-colors"
                      onClick={() => setShowPassword(!showPassword)}
                    >
                      {showPassword ? (
                        <EyeOff className="size-4 text-muted-foreground" />
                      ) : (
                        <Eye className="size-4 text-muted-foreground" />
                      )}
                    </InputGroupButton>
                  </InputGroupAddon>
                </InputGroup>
              </div>
              {error && <p className="text-sm text-red-500">{error}</p>}
              <Button type="submit" className="w-full" disabled={isLoading}>
                {isLoading ? "Saving..." : "Save new password"}
              </Button>
            </div>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}

"use client";
import { useRouter } from "next/navigation";
import { createClient } from "@/lib/supabase/client";
import { LogOut } from "lucide-react";
import React from "react";
import { cn } from "@/lib/utils";

type LogoutButtonProps = {
  children: React.ReactNode;
};

export function LogoutButton({
  children,
  className,
  onClick,
  ...props
}: LogoutButtonProps & React.ComponentProps<"button">) {
  const router = useRouter();

  const logout = async () => {
    // Sign out the user
    const supabase = createClient();
    await supabase.auth.signOut();

    // Redirect to login
    router.push("/auth/login");
  };

  return (
    <button
      className={cn(className, "cursor-pointer")}
      onClick={logout}
      {...props}
    >
      <LogOut className="mr-2" /> {children}
    </button>
  );
}

"use client";
import { useEffect, useState } from "react";
import {
  Card,
  CardContent,
  CardFooter,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { AlertCircle, ArrowRight, Ban, ShieldAlert } from "lucide-react";
import Link from "next/link";

const ERROR_MAP: Record<string, { title: string; desc: string; icon: any }> = {
  user_banned: {
    title: "Account Restricted",
    desc: "Your account has been suspended for violating our terms of service. If you think this is a mistake, please contact support.",
    icon: Ban,
  },
  access_denied: {
    title: "Access Denied",
    desc: "You don't have permission to access this resource or your login request was rejected.",
    icon: ShieldAlert,
  },
  default: {
    title: "Something went wrong",
    desc: "We couldn't complete your request. Please try signing in again.",
    icon: AlertCircle,
  },
};

export default function ErrorContent() {
  const [errorInfo, setErrorInfo] = useState(ERROR_MAP.default);
  const [rawCode, setRawCode] = useState<string | null>(null);

  useEffect(() => {
    // Parse the hash fragment (#error=...)
    const hash = window.location.hash.substring(1);
    const params = new URLSearchParams(hash);
    const errorCode = params.get("error_code") || params.get("error");

    if (errorCode && ERROR_MAP[errorCode]) {
      setErrorInfo(ERROR_MAP[errorCode]);
    }
    setRawCode(errorCode);
  }, []);

  const Icon = errorInfo.icon;

  return (
    <Card className="border-destructive/20 shadow-lg">
      <CardHeader className="text-center pb-2">
        <div className="mx-auto mb-4 flex h-12 w-12 items-center justify-center rounded-full bg-destructive/10 text-destructive">
          <Icon className="h-6 w-6" />
        </div>
        <CardTitle className="text-2xl font-bold tracking-tight">
          {errorInfo.title}
        </CardTitle>
      </CardHeader>
      <CardContent className="text-center">
        <p className="text-sm text-muted-foreground leading-relaxed">
          {errorInfo.desc}
        </p>
        {rawCode && (
          <code className="mt-4 block rounded bg-muted px-2 py-1 text-[10px] font-mono text-muted-foreground uppercase tracking-wider">
            Error ID: {rawCode}
          </code>
        )}
      </CardContent>
      <CardFooter className="flex gap-2">
        <Button className="flex-2" variant="default" asChild>
          <Link href="/auth/login">
            Sign In <ArrowRight />
          </Link>
        </Button>
        <Button className="flex-1" variant="secondary" asChild>
          <Link href="/" className="flex items-center gap-2">
            Go Home
          </Link>
        </Button>
      </CardFooter>
    </Card>
  );
}

"use client";

import { useState } from "react";
import { signInWithOAuth } from "@/app/actions/auth";
import { Button } from "@/components/ui/button";
import { Separator } from "@/components/ui/separator";
import { Spinner } from "@/components/ui/spinner";
import { useSearchParams } from "next/navigation";

type OAuthButtonsProps = {
  onError?: (error: string) => void;
  disabled?: boolean;
};

export function OAuthButtons({ onError, disabled }: OAuthButtonsProps) {
  const [isGoogleLoading, setIsGoogleLoading] = useState(false);
  const searchParams = useSearchParams();

  const handleSignIn = async (provider: "google") => {
    if (provider === "google") setIsGoogleLoading(true);

    try {
      // Extract the 'next' param, or default to dashboard/home
      const next = searchParams.get("next") || "/dashboard";
      // Call Server Action - no props needed!
      await signInWithOAuth(provider, next);
      // No need to handle redirect - Server Action does it via `redirect()`
    } catch (error: unknown) {
      const message =
        error instanceof Error
          ? error.message
          : `Failed to sign in with ${provider}`;
      onError?.(message);
      if (provider === "google") setIsGoogleLoading(false);
    }
  };

  return (
    <div className="flex flex-col gap-4">
      <Button
        variant="outline"
        className="w-full"
        onClick={() => handleSignIn("google")}
        disabled={isGoogleLoading || disabled}
      >
        {isGoogleLoading ? <Spinner /> : <GoogleIcon className="mr-2 size-5" />}
        Continue with Google
      </Button>

      <div className="relative mt-2 mb-6">
        <Separator />
        <span className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 bg-card px-2 text-xs text-muted-foreground">
          or continue with email
        </span>
      </div>
    </div>
  );
}

